import { Component, OnInit } from '@angular/core';
import { SummaryService } from '../../services/summary.service';
import { RevenueService, RevenueItem } from '../../services/revenue.service';
import { ExpensesService, ExpenseItem } from '../../services/expenses.service';

interface Summary {
  totalRevenue: number;
  totalExpenses: number;
  totalInvestments: number;
  netProfit: number;
  ownerShare: number;
  partnerShare: number;
}

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css']
})
export class DashboardComponent implements OnInit {
  summary: Summary | null = null;
  recentRevenue: RevenueItem[] = [];
  recentExpenses: ExpenseItem[] = [];

  constructor(
    private summaryService: SummaryService,
    private revenueService: RevenueService,
    private expensesService: ExpensesService
  ) {}

  ngOnInit(): void {
    this.loadSummary();
    this.loadRecentRevenue();
    this.loadRecentExpenses();
  }

  loadSummary(): void {
    // Load yearly summary for current year
    const currentYear = new Date().getFullYear();
    this.summaryService.getYearlySummary(currentYear).subscribe({
      next: (data) => {
        this.summary = {
          totalRevenue: parseFloat(data?.total_revenue_ll || '0'),
          totalExpenses: parseFloat(data?.total_expenses_ll || '0'),
          totalInvestments: 0,
          netProfit: parseFloat(data?.balance_ll || '0'),
          ownerShare: parseFloat(data?.owner1_share_ll || '0'),
          partnerShare: parseFloat(data?.owner2_share_ll || '0')
        };
      },
      error: (error) => {
        console.error('Error loading summary:', error);
        // Set default values if API fails
        this.summary = {
          totalRevenue: 0,
          totalExpenses: 0,
          totalInvestments: 0,
          netProfit: 0,
          ownerShare: 0,
          partnerShare: 0
        };
      }
    });
  }

  loadRecentRevenue(): void {
    this.revenueService.getRevenueWithLimit(5).subscribe({
      next: (data) => {
        this.recentRevenue = data;
      },
      error: (error) => {
        console.error('Error loading recent revenue:', error);
        this.recentRevenue = [];
      }
    });
  }

  loadRecentExpenses(): void {
    this.expensesService.getExpensesWithLimit(5).subscribe({
      next: (data) => {
        this.recentExpenses = data;
      },
      error: (error) => {
        console.error('Error loading recent expenses:', error);
        this.recentExpenses = [];
      }
    });
  }
}
<div class="dashboard">
  <div class="dashboard-header">
    <h1 class="dashboard-title">{{ 'DASHBOARD.TITLE' | translate }}</h1>
    <p class="dashboard-subtitle">{{ 'DASHBOARD.SUBTITLE' | translate }}</p>
  </div>

  <div class="dashboard-stats">
    <div class="stat-card">
      <div class="stat-icon">💰</div>
      <div class="stat-content">
        <h3 class="stat-value">${{ summary?.totalRevenue | number:'1.0-0' }}</h3>
        <p class="stat-label">{{ 'DASHBOARD.TOTAL_REVENUE' | translate }}</p>
      </div>
    </div>

    <div class="stat-card">
      <div class="stat-icon">💸</div>
      <div class="stat-content">
        <h3 class="stat-value">${{ summary?.totalExpenses | number:'1.0-0' }}</h3>
        <p class="stat-label">{{ 'DASHBOARD.TOTAL_EXPENSES' | translate }}</p>
      </div>
    </div>

    <div class="stat-card">
      <div class="stat-icon">📈</div>
      <div class="stat-content">
        <h3 class="stat-value">${{ summary?.totalInvestments | number:'1.0-0' }}</h3>
        <p class="stat-label">{{ 'INVESTMENTS.TOTAL_INVESTMENTS' | translate }}</p>
      </div>
    </div>

    <div class="stat-card">
      <div class="stat-icon">💎</div>
      <div class="stat-content">
        <h3 class="stat-value">${{ summary?.netProfit | number:'1.0-0' }}</h3>
        <p class="stat-label">{{ 'DASHBOARD.NET_PROFIT' | translate }}</p>
      </div>
    </div>
  </div>

  <div class="dashboard-grid">
    <div class="dashboard-card">
      <div class="card-header">
        <h2 class="card-title">{{ 'DASHBOARD.RECENT_REVENUE' | translate }}</h2>
        <a routerLink="/revenue" class="btn btn-secondary btn-sm">{{ 'DASHBOARD.VIEW_ALL' | translate }}</a>
      </div>
      <div class="card-content">
        <div class="table-responsive">
          <table class="table">
            <thead>
              <tr>
                <th>{{ 'COMMON.DATE' | translate }}</th>
                <th>{{ 'REVENUE.SOURCE' | translate }}</th>
                <th>{{ 'COMMON.AMOUNT' | translate }}</th>
              </tr>
            </thead>
            <tbody>
              <tr *ngFor="let item of recentRevenue">
                <td>{{ item.date | date:'shortDate' }}</td>
                <td>{{ item.source }}</td>
                <td class="text-right">${{ item.amount | number:'1.0-0' }}</td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>

    <div class="dashboard-card">
      <div class="card-header">
        <h2 class="card-title">{{ 'DASHBOARD.RECENT_EXPENSES' | translate }}</h2>
        <a routerLink="/expenses" class="btn btn-secondary btn-sm">{{ 'DASHBOARD.VIEW_ALL' | translate }}</a>
      </div>
      <div class="card-content">
        <div class="table-responsive">
          <table class="table">
            <thead>
              <tr>
                <th>{{ 'COMMON.DATE' | translate }}</th>
                <th>{{ 'EXPENSES.CATEGORY' | translate }}</th>
                <th>{{ 'COMMON.AMOUNT' | translate }}</th>
              </tr>
            </thead>
            <tbody>
              <tr *ngFor="let item of recentExpenses">
                <td>{{ item.date | date:'shortDate' }}</td>
                <td>{{ item.category }}</td>
                <td class="text-right">${{ item.amount | number:'1.0-0' }}</td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>

    <div class="dashboard-card">
      <div class="card-header">
        <h2 class="card-title">{{ 'DASHBOARD.OWNER_SHARE' | translate }}</h2>
        <a routerLink="/reports" class="btn btn-secondary btn-sm">{{ 'DASHBOARD.VIEW_ALL' | translate }}</a>
      </div>
      <div class="card-content">
        <div class="profit-distribution">
          <div class="profit-item">
            <span class="profit-label">{{ 'DASHBOARD.OWNER_SHARE' | translate }} (70%)</span>
            <span class="profit-value">${{ summary?.ownerShare | number:'1.0-0' }}</span>
          </div>
          <div class="profit-item">
            <span class="profit-label">{{ 'DASHBOARD.PARTNER_SHARE' | translate }} (30%)</span>
            <span class="profit-value">${{ summary?.partnerShare | number:'1.0-0' }}</span>
          </div>
        </div>
      </div>
    </div>

    <div class="dashboard-card">
      <div class="card-header">
        <h2 class="card-title">{{ 'COMMON.ACTIONS' | translate }}</h2>
      </div>
      <div class="card-content">
        <div class="quick-actions">
          <a routerLink="/revenue" class="btn btn-primary">
            <span>➕</span>
            {{ 'REVENUE.ADD_REVENUE' | translate }}
          </a>
          <a routerLink="/expenses" class="btn btn-danger">
            <span>➕</span>
            {{ 'EXPENSES.ADD_EXPENSE' | translate }}
          </a>
          <a routerLink="/investments" class="btn btn-success">
            <span>➕</span>
            {{ 'INVESTMENTS.ADD_INVESTMENT' | translate }}
          </a>
        </div>
      </div>
    </div>
  </div>
</div>
